import React, { useState } from 'react';
import { models } from '../../data/models';
import ModelCard from '../../components/ModelCard/ModelCard';
import './Models.css';

const SPECIALTIES = ['All', 'Runway & Editorial', 'Bridal & Commercial', 'Street & Ethnic', 'Luxury & Couture', 'Editorial & Runway', 'Commercial & Print'];

function Models() {
  const [filter, setFilter] = useState('All');
  const [search, setSearch] = useState('');

  const filtered = models.filter((m) => {
    const matchFilter = filter === 'All' || m.specialty === filter;
    const matchSearch = m.name.toLowerCase().includes(search.toLowerCase()) ||
      m.location.toLowerCase().includes(search.toLowerCase());
    return matchFilter && matchSearch;
  });

  return (
    <div className="models-page">
      <div className="page-hero">
        <h1>Our Models</h1>
        <p>Meet the talented professionals who bring our events to life</p>
      </div>

      <div className="container models-page__body">
        {/* Controls */}
        <div className="models-page__controls">
          <input
            type="text"
            placeholder="🔍  Search by name or city..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{ maxWidth: '360px' }}
          />
          <div className="models-page__filters">
            {SPECIALTIES.map((s) => (
              <button
                key={s}
                className={`filter-btn ${filter === s ? 'active' : ''}`}
                onClick={() => setFilter(s)}
              >
                {s}
              </button>
            ))}
          </div>
        </div>

        <p style={{ fontSize: '0.9rem', color: 'var(--text-gray)', marginBottom: '28px' }}>
          Showing <strong>{filtered.length}</strong> model{filtered.length !== 1 ? 's' : ''}
        </p>

        {filtered.length > 0 ? (
          <div className="models-grid">
            {filtered.map((model) => (
              <ModelCard key={model.id} model={model} />
            ))}
          </div>
        ) : (
          <div style={{ textAlign: 'center', padding: '60px 0', color: 'var(--text-gray)' }}>
            <p style={{ fontSize: '1.1rem' }}>👗 No models found matching your criteria.</p>
            <button className="btn-outline" style={{ marginTop: '16px' }} onClick={() => { setFilter('All'); setSearch(''); }}>
              Clear Filters
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

export default Models;
